  padding: 4px 10px;
  border-radius: 8px;
  background: #ffebee;
  color: #b71c1c;
}
.vuln-card.high .vuln-cvss-pill { background: #fff3e0; color: #e65100; }
.vuln-kv-grid {
  display: grid;
  grid-template-columns: minmax(100px, 120px) 1fr;
  gap: 8px 14px;
  font-size: 0.88em;
  margin-top: 12px;
  align-items: start;
}
.vuln-kv-grid .k {
  color: var(--text-secondary);
  font-weight: 600;
}
.vuln-kv-grid .v { word-break: break-word; }
.vuln-kv-grid .v.mono {
  font-family: ui-monospace, Menlo, Consolas, monospace;
  font-size: 0.8em;
  line-height: 1.5;
  background: #fff;
  padding: 8px 10px;
  border-radius: 6px;
  border: 1px solid var(--border);
}
.vuln-block-label {
  font-size: 0.72em;
  letter-spacing: 0.06em;
  color: var(--primary);
  font-weight: 700;
  margin-top: 14px;
  margin-bottom: 6px;
}
.vuln-extra {
  background: #f5f5f5;
  border-radius: 6px;
  padding: 10px 12px;
  font-size: 0.85em;
